   144→    if (saveCredentials) {
   145→      // Cache user password
   146→      await _profileStorage.setPassword(password);
   147→    } else {
   148→      // Remove cached user password
   149→      await _profileStorage.setPassword(null);
   150→    }
   151→
   152→    await _profileStorage.setUserId(userId);
