   165→    final user = userInfoResult.right.user;
   166→    final teamId = user.teams
   167→        .where((t) =>
   168→            user.givenUserRoles[t.id!]
   169→                ?.where((r) => !r.deleteFlag)
   170→                .isNotEmpty ??
