/// {@category Data}
library;

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:amplify_auth_cognito/amplify_auth_cognito.dart';
import 'package:amplify_flutter/amplify_flutter.dart';
import 'package:fimber/fimber.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/clients/api_server_client.dart';
import 'package:baseball_detector_flutter/data/models/dto/user/email_verification_status_response.dart';
import 'package:baseball_detector_flutter/data/models/dto/user/password_change_request.dart';
import 'package:baseball_detector_flutter/data/models/dto/user/password_reset_request.dart';
import 'package:baseball_detector_flutter/data/models/dto/user/set_user_initial_password_request.dart';
import 'package:baseball_detector_flutter/data/models/dto/user/sign_up_request.dart';
import 'package:baseball_detector_flutter/data/models/dto/user/sign_up_response.dart';
import 'package:baseball_detector_flutter/data/models/dto/user/user_detail_response.dart';
import 'package:baseball_detector_flutter/data/models/dto/user/verify_code_request.dart';
import 'package:baseball_detector_flutter/data/models/dto/user/verify_code_response.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure_code.dart';
import 'package:baseball_detector_flutter/data/profile_storage.dart';
import 'package:baseball_detector_flutter/data/query_runner.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/modules/amplify/amplify.dart';

abstract class AuthClient {
  Future<Result<Failure, bool>> signInWithPassword(
    String email,
    String password,
    bool saveCredentials,
  );

  Future<Result<Failure, bool>> signOut();

  Future<Result<Failure, bool>> changePassword({
    required String newPassword,
    required bool saveCredentials,
  });

  Future<Result<Failure, bool>> forgotPassword({required String email});

  Future<Result<Failure, String>> signUp({
    required String email,
    required String password,
    DateTime? birthday,
  });

  Future<Result<Failure, void>> resendCode({required String email});

  Future<Result<Failure, String>> verifyCode({required String code});

  Future<Result<Failure, void>> completeSignUp({required String token});

  Future<Result<Failure, bool>> deleteAccount();

  Future<bool> get isLoggedIn;
}

class AuthClientImpl extends AuthClient {
  static final _fc = failureCodeBuilder.category('AAC'); // Auth-AuthClient
  static final _logger = FimberLog('AuthClient');

  late final APIServerClient _apiClient;

  QueryRunner get _runner => _apiClient.runner;

  /// local storage provider
  final ProfileStorage _profileStorage;

  /// Default constructor
  AuthClientImpl(
    this._profileStorage,
    Locale locale,
    String? appVersion,
  ) {
    _apiClient = APIServerClient(
      locale: locale,
      appVersion: appVersion,
    );
  }

  @override

  /// Sign in user to the application with email and password
  Future<Result<Failure, bool>> signInWithPassword(
      String email, String password, bool saveCredentials) async {
    final methodFc = _fc.category('SIP');

    // Run the query and return result.
    final result = await _runner.runQuery(
      () async {
        if (await AuthUtils.instance.isSignedIn()) {
          await AuthUtils.instance.signOut();
        }
        await Amplify.Auth.signIn(
          username: email,
          password: password,
          options: const SignInOptions(
            pluginOptions: CognitoSignInPluginOptions(
              authFlowType: AuthenticationFlowType.userPasswordAuth,
            ),
          ),
        );
      },
      false,
    );
    if (result.hasLeft) {
      if (result.left is NetworkFailure) {
        return Left(Failure.network(
          code: methodFc.position('001'),
          description: (l10n) =>
              l10n.auth_client__failed_to_authenticate_check_network,
          underlyingException: result.left.underlyingException,
        ));
      }
      if (result.left is InvalidSessionFailure) {
        final e = result.left.underlyingException;
        if (e is AuthException) {
          return Left(await _processAuthException(
            e,
            email: email,
            password: password,
          ));
        }
      }
      return Left(result.left);
    }

    late String userId;
    try {
      userId = await AuthUtils.instance.getUserId();
    } catch (e, stackTrace) {
      _logger.e('failed to get userId', ex: e, stacktrace: stackTrace);
      return Left(Failure.undefined(
        code: methodFc.position('002'),
        underlyingException: e,
        stackTrace: stackTrace,
      ));
    }

    await _profileStorage.setEmail(email);
    if (saveCredentials) {
      // Cache user password
      await _profileStorage.setPassword(password);
    } else {
      // Remove cached user password
      await _profileStorage.setPassword(null);
    }

    await _profileStorage.setUserId(userId);

    // Get team_id and role of the user using direct API call
    // This avoids circular dependency with Repository
    final userInfoResult = await _apiClient.request(
      method: 'GET',
      path: '/users/me',
      responseMapper: UserDetailResponse.fromJson,
    );
    if (userInfoResult.hasLeft) {
      return Left(userInfoResult.left);
    }

    final user = userInfoResult.right.user;
    final teamId = user.teams
        .where((t) =>
            user.givenUserRoles[t.id!]
                ?.where((r) => !r.deleteFlag)
                .isNotEmpty ??
            false)
        .firstOrNull
        ?.id;
    if (teamId == null) {
      return Left(Failure.undefined(
        code: methodFc.position('003'),
        description: (l10n) => 'User does not belong to any team',
      ));
    }

    // Cache team_id and role
    await _profileStorage.setTeamId(teamId);

    return const Right(true);
  }

  Future<Failure> _processAuthException(
    AuthException e, {
    required String email,
    required String password,
  }) async {
    final methodFc = _fc.category('PAEX');

    final isPasswordIncorrect = e is AuthNotAuthorizedException ||
        (e is UserNotFoundException &&
            e.message == "UserMigration failed with error Incorrect password.");
    final isUserNotFound =
        e is UserNotFoundException && e.message == "User does not exist.";

    if (isPasswordIncorrect) {
      // パスワードが間違っている場合でも、メール確認状況をチェック
      final emailStatusResult = await _getEmailVerificationStatus(
        email: email,
        password: password,
      );
      // もしメール未確認の場合は、そちらのエラーを返す
      if (emailStatusResult is UnconfirmedEmailFailure) {
        return emailStatusResult;
      }
      // それ以外の場合は、パスワード間違いエラーを返す
      return Failure.incorrectPassword(
        code: methodFc.position('001'),
        email: email,
      );
    }
    if (isUserNotFound) {
      return await _getEmailVerificationStatus(
        email: email,
        password: password,
      );
    }

    // アカウント削除後にユーザーが削除予定に入っている場合に signIn しようとすると
    // このエラーになる。この場合は未登録メールアドレスエラーを返す。
    final errorCode = methodFc.position('003');
    if (errorCode == 'EM-AAC-PAEX-003') {
      return Failure.unregisteredEmail(
        code: errorCode,
        email: email,
      );
    }

    // それ以外の認証エラーは UndefinedFailure として扱う
    return Failure.undefined(
      code: methodFc.position('004'),
      description: (l10n) =>
          l10n.auth_client__failed_to_authenticate_received_error_response,
      underlyingException: e,
    );
  }

  Future<Failure> _getEmailVerificationStatus({
    required String email,
    required String password,
  }) async {
    final methodFc = _fc.category('GVS');

    // Run the query and return result.
    final result = await _apiClient.request(
      method: 'GET',
      path:
          '/auth/users/verification-status?email=${Uri.encodeQueryComponent(email)}',
      responseMapper: EmailVerificationStatusResponse.fromJson,
      authenticated: false,
    );
    if (result.hasLeft) {
      return result.left;
    }

    final status = result.right.status;
    switch (status) {
      case EmailVerificationStatus.notVerified:
        // メール未検証の場合
        // この場合には localStorage に保存されている email, password, birthday の情報が
        // このユーザーのものでない可能性があるため上書きする
        // またメール未検証ということは一度 signUp をしているためサーバー上には birthday の情報がある
        // そのため birtyday は null にして良い
        // See also: https://knowhere-org.slack.com/archives/C080L18MC7M/p1759482517683899?thread_ts=1759457850.493329&cid=C080L18MC7M
        await _profileStorage.setEmail(email);
        await _profileStorage.setPassword(password);
        await _profileStorage.setUserBirthday(null);
        return Failure.unconfirmedEmail(
          code: methodFc.position('001'),
          email: email,
        );
      case EmailVerificationStatus.notCreated:
        return Failure.unregisteredEmail(
          code: methodFc.position('002'),
          email: email,
        );
      default:
        return Failure.undefined(
          code: methodFc.position('003'),
          description: (l10n) => l10n.auth_client__unknown_verification_status,
        );
    }
  }

  @override

  /// Sign out user from application
  Future<Result<Failure, bool>> signOut() async {
    // TODO: After disconnecting network,
    // goTrueClient.signOut() throws a network exception at the first call,
    // but this method return null without any exceptions at the second call.

    // Run the query and return result.
    final result = await _runner.runQuery(
      () => AuthUtils.instance.signOut(),
    );
    // Delete cache regardless of the result
    await Future.wait([
      _profileStorage.setUserId(null),
      _profileStorage.setTeamId(null),
    ]);
    if (result.hasLeft) {
      return Left(result.left);
    } else {
      return const Right(true);
    }
  }

  @override
  Future<Result<Failure, bool>> changePassword(
      {required String newPassword, required bool saveCredentials}) async {
    // Run the query and return result.
    final result = await _apiClient.request(
      method: 'PUT',
      path: '/users/me/password',
      data: PasswordChangeRequest(
        password: newPassword,
        passwordConfirmation: newPassword,
      ).toJson(),
    );
    if (result.hasLeft) {
      return Left(result.left);
    }

    if (saveCredentials) {
      // Save if we need to save credentials
      await _profileStorage.setPassword(newPassword);
    } else {
      // Remove cached user password
      await _profileStorage.setPassword(null);
    }
    return const Right(true);
  }

  @override
  Future<Result<Failure, bool>> forgotPassword({required String email}) async {
    // Run the query and return result.
    final result = await _apiClient.request(
      method: 'POST',
      path: '/auth/password-reset/email',
      data: PasswordResetRequest(
        email: email,
      ).toJson(),
      authenticated: false,
    );
    if (result.hasLeft) {
      return Left(result.left);
    }
    return const Right(true);
  }

  @override
  Future<Result<Failure, String>> signUp({
    required String email,
    required String password,
    DateTime? birthday,
  }) async {
    // Run the query and return result.
    final result = await _apiClient.request(
      method: 'POST',
      path: '/auth/signup',
      data: SignUpRequest(
        name: email,
        email: email,
        password: password,
        birthday: birthday,
      ).toJson(),
      responseMapper: SignUpResponse.fromJson,
      authenticated: false,
    );
    if (result.hasLeft) {
      return Left(result.left);
    }

    final userId = result.right.userId;
    await Future.wait([
      _profileStorage.setIsInSignUpFlow(true),
      _profileStorage.setEmail(email),
      _profileStorage.setPendingSignUpUserId(userId),
      _profileStorage.setUserId(userId),
      _profileStorage.setPassword(password),
      _profileStorage.setUserBirthday(birthday),
    ]);
    return Right(userId);
  }

  @override
  Future<Result<Failure, String>> verifyCode({
    required String code,
  }) async {
    final email = await _profileStorage.getEmail();
    assert(email != null);

    // Run the query and return result.
    final result = await _apiClient.request(
      method: 'GET',
      path: '/auth/code-verification',
      queryParameters: VerifyCodeRequest(
        email: email!,
        code: code,
      ).toJson(),
      responseMapper: VerifyCodeResponse.fromJson,
      authenticated: false,
    );
    if (result.hasLeft) {
      return Left(result.left);
    }
    return Right(result.right.token);
  }

  @override
  Future<Result<Failure, void>> completeSignUp({required String token}) async {
    final pendingUserId = _profileStorage.getPendingSignUpUserId();
    final userId = pendingUserId ?? _profileStorage.getUserId();
    final password = await _profileStorage.getPassword();

    assert(userId != null);
    assert(password != null);

    // Run the query and return result.
    final result = await _apiClient.request(
